import{_ as i,o as r,c as l,a4 as b}from"./chunks/framework.EYT3XhWU.js";const a=JSON.parse('{"title":"篇章阅读","description":"","frontmatter":{},"headers":[],"relativePath":"行测/言语理解/篇章阅读.md","filePath":"行测/言语理解/篇章阅读.md"}'),e={name:"行测/言语理解/篇章阅读.md"};function s(t,o,p,x,n,d){return r(),l("div",null,[...o[0]||(o[0]=[b('<h1 id="篇章阅读" tabindex="-1">篇章阅读 <a class="header-anchor" href="#篇章阅读" aria-label="Permalink to “篇章阅读”">​</a></h1><p>字数: 8224 字 时长: 30 分钟 <strong>VIP文档</strong></p><h2 id="一、什么是篇章阅读" tabindex="-1">一、什么是篇章阅读 <a class="header-anchor" href="#一、什么是篇章阅读" aria-label="Permalink to “一、什么是篇章阅读”">​</a></h2><ol><li><p>篇章阅读在国考三种类型里，属于国考（副省级）考试特色题目。省考包括北京、上海、江苏会考篇章阅读。</p></li><li><p>一般给你一篇文章，大概1000字以上，对应多个问题，问题选词填空、词句理解、推断下文、细节查找题、句子或段落填空、标题添加、主旨观点等。根据问法形式确定题型后，就可以针对各题型的具体要求进行做答了。</p></li><li><p>问题就按照之前学的技巧解题。比如主旨题类当成中心理解题做，细节判断题类要知道常见的错误类型：无中生有、偷换概念、偷换逻辑等等。</p></li><li><p><strong>篇章阅读的四个命题思维</strong>：</p><ol><li>（1）重视对原文内容的考查。篇章阅读重点考查原文内容的重现，因此无须过度引申理解，只需快速定位、查找题干的信息解题即可。</li><li>（2）题目难度与阅读难度成反比。常见的篇章阅读材料有两大类，分别是科技说明类与人文社科类，单纯从阅读难度的角度来说，科技说明类的文章比较深奥，而人文社科类的文章相对易懂，但是命题人在出题时往往会把科技说明类文章的题目设置得相对简单，而把人文社科类文章的题目设置得较有难度。</li><li>（3）题目顺序与文段顺序大体一致。大体上每个篇章阅读的题目，除了涉及全篇的中心理解题及全篇的细节判断题需要通篇把握外，其他题目的顺序与文段的顺序基本一致。</li><li>（4）文段内容“雨露均沾”。即出题人设置题目会尽可能每一段都有涉猎，遇到全文细节时，可以多关注没有出过题目的段落。</li></ol></li><li></li></ol><h2 id="二、解题技巧" tabindex="-1">二、解题技巧 <a class="header-anchor" href="#二、解题技巧" aria-label="Permalink to “二、解题技巧”">​</a></h2><ol><li><strong>1、先看题目，后读文章</strong>。由于文章阅读的文章字数偏多，那么我们要记住每个文段的一些细节的内容几乎是不可能的。因此我们要先了解，题目让我们找些什么，问了我们什么，才能抓住解题关键。</li><li><strong>2、微观题目边读边做</strong>。微观题目是指通过阅读问法可以明确在文段那一段落的题目，包括逻辑填空、词句理解、推断下文、细节查找题等，这类题目建议可以优先去做，可以读完题目，定位材料，边读材料边做，而且题目的设置一般是按照文章的顺序进行的，这样当我们把微观题目做完，基本对文章的大意也有了一定把握，再来做宏观类题目就能事半功倍。</li><li><strong>3、重点关注材料的首尾段以及各段落的首尾句</strong>。明确每个段落的段落话题及在文章中的功能，这样在做宏观类题目的时候就不需要重复阅读，也就能够快速概括文章主旨了。</li><li><strong>4、宏观题目读完再做</strong>。宏观题目指的是通过阅读问法无法判断指向哪一段落，或是需要立足全文来解答的题目，包括标题添加题、主旨观点题、细节判断题等，这类题目就可以做完微观类题目，掌握文章大意之后再来做，难度就大大降低了。</li></ol><h2 id="三、随笔练习" tabindex="-1">三、随笔练习 <a class="header-anchor" href="#三、随笔练习" aria-label="Permalink to “三、随笔练习”">​</a></h2><p>例1、2021国家</p><ol><li><p>消费品企业有充分的理由去开展数字化转型。消费端是最活跃的市场，对消费者和消费市场的理解早已融入消费品企业的基因，数字化则为消费品企业提供了全新的消费者洞察机会。①</p></li><li><p>首先，消费品企业进行数字化转型的动力之一是增加与消费者的互动。多年前，消费群体几乎是隐形的，企业通过发邮件或在电视上打广告的方式来做营销。在数字化的今天，企业营销开始注重每一位个体消费者，强调点对点的互动。数字化做得好的消费品企业会去了解每一个消费个体的喜好和行为，从而获得非常细致的消费洞见——某个消费者喜欢什么样的产品，什么样的促销活动适合这位消费者，以及何时是联系这位消费者的最佳时机等。②</p></li><li><p>消费品企业的第二项数字化转型动力是提供数字产品和服务，以及用数字化的方式销售产品和服务。长期以来，消费者熟知的大型消费企业需要通过层层分销才能将产品送入零售终端，这里面存在很大的优化空间。数字化时代出现了更多直接面向消费者的营销渠道，企业不仅能够通过这些渠道销售实物产品，也能提供数字化的产品和服务。③</p></li><li><p>消费品企业的第三项数字化转型动力是提升运营效率。金融、互联网技术、人力资源领域中，不少此前由人来完成的工作，目前已经可以被数字工具替代。例如，一些公司设计出算法，从大批简历中筛选重点信息，为应聘者打分，快速向人力资源部推荐理想的候选者。我们会看到越来越多此类数字化技术提升运营工作效率的例子。对于消费品企业来说，运营效率的提升意味着可以将更多资源投入到理解消费者、进行品牌建设以及开发产品等核心业务中。④</p></li><li><hr></li><li><p><strong>1.下面这段文字最适合放在文中的哪个位置？</strong></p></li><li><p>例如，营养食品公司提供可供下载体验的App产品，消费者在App上不仅可以购买产品，也可以获得来自品牌的营养建议；时尚企业则可以开发自营销售的App平台，同时为消费者提供服饰穿搭建议。因此，数字渠道既是出色的销售渠道，也可以为消费者提供数字产品和服务。</p></li><li><p>A.①  B.②  C.③  D.④</p><details open="" style="box-sizing:border-box;"><summary style="box-sizing:border-box;touch-action:manipulation;margin:16px 0px;">解析</summary><blockquote style="box-sizing:border-box;margin:16px 0px;border-left:4px solid rgb(46, 46, 50);padding-left:16px;transition:border-color 0.5s;color:rgb(152, 152, 159);">先看题目，语句填空，给定的语句以“例如”开头，以“因此”结尾；说明其是对前面话题的举例说明，又通过“因此”来总结了该话题；<br style="box-sizing:border-box;">所以我们通过例子和总结来定位话题，带着话题回材料为其找落脚点。<br style="box-sizing:border-box;">观察文段，先尝试看每段首句，看首句是否可以确定该段落话题。第③段的主题是介绍“消费品企业的第二项数字化转型动力是提供数字产品和服务，以及用数字化的方式销售产品和服务”，且尾句引出“营销渠道”的话题，与题干话题一致，C项当选。<br style="box-sizing:border-box;">第①段为文章开篇话题引入，介绍数字化为企业提供了全新的观察消费者的机会；第②段强调的重点为“消费品企业进行数字化转型的动力之一是增加与消费者的互动”；第④段强调的重点为“消费品企业的第三项数字化转型动力是提升运营效率”，均与题干观点不一致，衔接不恰当，排除。<br style="box-sizing:border-box;">故正确答案为C。</blockquote></details></li><li><hr></li><li><p><strong>2.下列哪一内容未在文中明确提及？</strong></p></li><li><p>A.数字化能够使消费品企业的工作效率提高</p></li><li><p>B.消费品企业可以依托数字化了解用户需求</p></li><li><p>C.消费品企业的数字化转型依赖可信的数据</p></li><li><p>D.消费品企业借助数字化技术优化销售环节</p><details open="" style="box-sizing:border-box;"><summary style="box-sizing:border-box;touch-action:manipulation;margin:16px 0px;">解析</summary><blockquote style="box-sizing:border-box;margin:16px 0px;border-left:4px solid rgb(46, 46, 50);padding-left:16px;transition:border-color 0.5s;color:rgb(152, 152, 159);">先看题目，细节判断题，上一题我们看了每个段落的首句，不难发现整篇材料的行文结构为：总-分结构，第一段提出观点“数字化转型”的好处；第二、三、四段分别说明三方面的好处。每个段落的首句同样是总分结构，首句即为主旨句。<br style="box-sizing:border-box;">A项，根据文章第④段首句可知，数字化可以提高消费品企业的工作效率，表述正确，排除；<br style="box-sizing:border-box;">B项，根据文章第②段可知，企业可以依托数字化了解每位用户的需求，表述正确，排除；<br style="box-sizing:border-box;">C项，“数字化转型依赖可信的数据”无中生有，文章并未提及，表述错误，当选；<br style="box-sizing:border-box;">D项，根据文章第③段“长期以来，消费者熟知的大型消费企业需要通过层层分销才能将产品送入零售终端，这里面存在很大的优化空间”可知，企业可以通过数字化来优化销售环节，表述正确，排除。<br style="box-sizing:border-box;">本题为选非题，故正确答案为C。</blockquote></details></li><li><hr></li><li><p><strong>3.这篇文章意在说明：</strong></p></li><li><p>A.消费品企业面临数字化转型压力</p></li><li><p>B.消费品企业应该拓展转型途径</p></li><li><p>C.数字化为企业用户提供消费指南</p></li><li><p>D.数字化为消费品企业转型赋能</p><details open="" style="box-sizing:border-box;"><summary style="box-sizing:border-box;touch-action:manipulation;margin:16px 0px;">解析</summary><blockquote style="box-sizing:border-box;margin:16px 0px;border-left:4px solid rgb(46, 46, 50);padding-left:16px;transition:border-color 0.5s;color:rgb(152, 152, 159);">先看题目，中心理解题，基于前两题对材料的分析，这道归类为难的题目已经不再难了，可以直接看选项。<br style="box-sizing:border-box;">文章开篇论述了消费品企业有充分的理由进行数字化转型，指出数字化为消费品企业提供了全新的消费者洞察机会。之后从三个方面具体阐述了消费品企业进行数字化转型的动力。故文章重点强调数字化对消费品企业转型的作用，对应D项。<br style="box-sizing:border-box;">A项，文章未提及“数字化转型压力”，无中生有，排除；<br style="box-sizing:border-box;">B项，文章并未提及“拓展转型途径”，无中生有，排除；<br style="box-sizing:border-box;">C项，仅对应文章第③段的内容，片面且非重点，排除。<br style="box-sizing:border-box;">故正确答案为D。</blockquote></details></li></ol><p>例2、2023北京</p><ol><li><p>有两名司机曾经在车中亲身体验过龙卷风从身边吹过的恐怖。好在这股龙卷风正处于衰退末期，否则他们的卡车分分钟会被吹飞。但即便是衰退末期，这股龙卷风依然能使他们感受到强烈压迫感。车身不停地震颤，他们神经紧绷，生怕下一秒就会丢掉性命。其实，当遭遇强龙卷风时，最好能利用十字路口，朝龙卷风行进轨迹相反或直角的方向，快速逃离；如果来不及逃离，可就近寻找最低洼地点并迅速躺卧。</p></li><li><p>东半球西太平洋的风暴被称为台风，西半球大西洋和东太平洋的风暴被称为飓风，而南太平洋和印度洋的风暴则被称为气旋。龙卷风比上面提到的风暴更具破坏力。龙卷风中心附近风速在每秒钟100米到200米，最大可达每秒钟300米，比台风近中心最大风速大好几倍。龙卷风范围小，但很集中，所以破坏力更强，而且与台风几天前就可以被监测到不同，龙卷风只能提前10分钟左右被监测到。</p></li><li><p>①龙卷风是怎么形成的？又是如何消失的？人类目前尚未完全了解这个“恐怖的怪物”。我们只知道，龙卷风是一种剧烈旋转的气柱，横亘在地球表面与云层之间，通常与积雨云有关联。②然而，大型龙卷风会持续更长时间，大约30分钟。据记载，最强龙卷风的风速超过每小时483千米，能把建筑物连根拔起，其空中直径超过3.2千米，几十千米内万物遭劫。最猛烈的龙卷风源自于所谓的超级单体雷暴，这种雷暴和普通雷暴的形成要素一样——地表的气流温暖湿润，上方的气流相对较冷且干燥。③接着，像热气球一样，温暖的气流开始上升，初具形成雷暴的条件。而要形成超级单体雷暴还需要风力增强、风向随高度改变、上升气流极速旋转等更多条件。超级单体雷暴形成后，在高空搅动，其区域下方就会有30%的概率形成龙卷风。这是因为超级单体雷暴中的气流下沉，就会引起地面附近的气流随之旋转。④然而，令科学家苦恼的是，有些雷暴会带来龙卷风，有一些则不会。</p></li><li><hr></li><li><p><strong>1.文章第一段意在：</strong></p></li><li><p>A.呈现一次具体的龙卷风事件</p></li><li><p>B.分享遭遇龙卷风的传奇经历</p></li><li><p>C.强调环境对躲避龙卷风的意义</p></li><li><p>D.以遭遇龙卷风的实例引出主题</p><details open="" style="box-sizing:border-box;"><summary style="box-sizing:border-box;touch-action:manipulation;margin:16px 0px;">解析</summary><blockquote style="box-sizing:border-box;margin:16px 0px;border-left:4px solid rgb(46, 46, 50);padding-left:16px;transition:border-color 0.5s;color:rgb(152, 152, 159);">先看题目，中心理解题，而且问第一段。<br style="box-sizing:border-box;">定位文章第一段。文段开篇引出两名司机遭遇龙卷风这一背景，接着指出这股龙卷风正处于衰退末期，但他们仍然感受到了强烈的压迫感，尾句通过“其实”介绍了遭遇强龙卷风时的避险措施，文章后两段分别论述了龙卷风的破坏性和风速及其形成方式。故综合来看，文章第一段意在以两名司机遭遇龙卷风的实例引出龙卷风这一主题，对应D项。<br style="box-sizing:border-box;">A项，文章第一段仅体现了两名司机遭遇龙卷风时的感受，并未论述此事件发生的时间、地点及详细内容，无中生有，排除；<br style="box-sizing:border-box;">B项，“传奇经历”文段未提及，无中生有，排除；<br style="box-sizing:border-box;">C项，“环境对躲避龙卷风的意义”文段未提及，无中生有，排除。<br style="box-sizing:border-box;">故正确答案为D。</blockquote></details></li><li><hr></li><li><p><strong>2.“气象学家告诉我们，大部分龙卷风通常持续时长不到10分钟。”这句话最适合放在文中哪个位置？</strong></p></li><li><p>A.①  B.②  C.③  D.④</p><details open="" style="box-sizing:border-box;"><summary style="box-sizing:border-box;touch-action:manipulation;margin:16px 0px;">解析</summary><blockquote style="box-sizing:border-box;margin:16px 0px;border-left:4px solid rgb(46, 46, 50);padding-left:16px;transition:border-color 0.5s;color:rgb(152, 152, 159);">先看题目，语句填空，文字主要围绕龙卷风的持续时间进行论述，且强调龙卷风持续时间短，故前文或后文应与龙卷风的持续时间有关。<br style="box-sizing:border-box;">②处后“然而”表示转折，转折后通过“大型龙卷风会持续更长时间”表示大型龙卷风持续时间会比较久，放在②之前可以与题干文字构成前后相反的转折关系，且话题一致，对应B项。<br style="box-sizing:border-box;">①处后提出龙卷风形成与消失的问题，③处后论述雷暴形成的具体条件，④处后转折词“然而”后论述科学家的苦恼，均与题干内容无关，排除A、C、D三项。<br style="box-sizing:border-box;">故正确答案为B。</blockquote></details></li><li><hr></li><li><p><strong>3.关于龙卷风，本文没有提到：</strong></p></li><li><p>A.命名规则</p></li><li><p>B.破坏力</p></li><li><p>C.影响范围</p></li><li><p>D.中心附近风速</p><details open="" style="box-sizing:border-box;"><summary style="box-sizing:border-box;touch-action:manipulation;margin:16px 0px;">解析</summary><blockquote style="box-sizing:border-box;margin:16px 0px;border-left:4px solid rgb(46, 46, 50);padding-left:16px;transition:border-color 0.5s;color:rgb(152, 152, 159);">A项，龙卷风的“命名规则”在文中并未提及，当选；<br style="box-sizing:border-box;">B项，根据第二段的“龙卷风比上面提到的风暴更具破坏力······龙卷风范围小，但很集中，所以破坏力更强”可知，“破坏力”在文中有所提及，排除；<br style="box-sizing:border-box;">C项，根据第三段“龙卷风范围小”和“最强龙卷风······空中直径超过3.2千米，几十千米内万物遭劫”可知，“影响范围”在文中有所提及，排除；<br style="box-sizing:border-box;">D项，根据第二段“龙卷风中心附近风速在每秒钟100米到200米，最大可达每秒钟300米”可知，“中心附近风速”在文中有所提及，排除。<br style="box-sizing:border-box;">本题为选非题，故正确答案为A。</blockquote></details></li><li><hr></li><li><p><strong>4.根据文意，下列说法正确的是：</strong></p></li><li><p>A.台风、飓风、气旋都属于龙卷风</p></li><li><p>B.超级单体雷暴引起龙卷风的概率低于三分之一</p></li><li><p>C.最强龙卷风空中直径最长可达400千米</p></li><li><p>D.龙卷风可以提前几天被监测到</p><details open="" style="box-sizing:border-box;"><summary style="box-sizing:border-box;touch-action:manipulation;margin:16px 0px;">解析</summary><blockquote style="box-sizing:border-box;margin:16px 0px;border-left:4px solid rgb(46, 46, 50);padding-left:16px;transition:border-color 0.5s;color:rgb(152, 152, 159);">A项，根据第二段“东半球西太平洋的风暴被称为台风，西半球大西洋和东太平洋的风暴被称为飓风，而南太平洋和印度洋的风暴则被称为气旋。龙卷风比上面提到的风暴更具破坏力”可知，“台风、飓风、气旋”均属于风暴，而非“龙卷风”，表述错误，排除；<br style="box-sizing:border-box;">B项，根据第三段“超级单体雷暴形成后，在高空搅动，其区域下方就会有30%的概率形成龙卷风”可知，表述正确，当选；<br style="box-sizing:border-box;">C项，根据第三段“据记载，最强龙卷风的风速超过每小时483千米，能把建筑物连根拔起，其空中直径超过3.2千米，几十千米内万物遭劫”可知，“空中直径最长可达400千米”偷换概念，排除；<br style="box-sizing:border-box;">D项，根据第二段“龙卷风范围小，但很集中，所以破坏力更强，而且与台风几天前就可以被监测到不同，龙卷风只能提前10分钟左右被监测到”可知，“可以提前几天被监测到”表述错误，排除。<br style="box-sizing:border-box;">故正确答案为B。</blockquote></details></li><li><hr></li><li><p><strong>5.最适合作本文标题的是：</strong></p></li><li><p>A.人类如何监测龙卷风</p></li><li><p>B.龙卷风灾害逃生指南</p></li><li><p>C.“恐怖的怪物”龙卷风</p></li><li><p>D.我们能战胜龙卷风吗</p><details open="" style="box-sizing:border-box;"><summary style="box-sizing:border-box;touch-action:manipulation;margin:16px 0px;">解析</summary><blockquote style="box-sizing:border-box;margin:16px 0px;border-left:4px solid rgb(46, 46, 50);padding-left:16px;transition:border-color 0.5s;color:rgb(152, 152, 159);">基于前两题对材料的分析，文章第一段通过实例介绍龙卷风到来时强烈的压迫感和恐怖感，并指出遭遇强龙卷风时的应对方法。<br style="box-sizing:border-box;">第二段介绍龙卷风破坏力强且监测难度大。<br style="box-sizing:border-box;">第三段具体介绍了龙卷风的破坏性及雷暴与龙卷风的关系。<br style="box-sizing:border-box;">文章从龙卷风的破坏力、监测难度、形成原因等多个方面对龙卷风展开介绍，对应C项。<br style="box-sizing:border-box;">A项，“监测龙卷风”仅对应第二段的一部分内容，非重点，且“如何监测”文章并未提及，无中生有，排除；<br style="box-sizing:border-box;">B项，“逃生指南”仅对应第一段的一部分内容，非重点，排除；<br style="box-sizing:border-box;">D项，“战胜龙卷风”文章并未提及，无中生有，排除。<br style="box-sizing:border-box;">故正确答案为C。</blockquote></details></li></ol><p>例3、2023国家</p><ol><li><p>降雨来源于云层，云层中的水蒸气遇到冷空气或某些成核物质后，就会很快冷凝而降落下来，所以冷暖空气相遇之处就是雨水多发的地带，这就是天气预报的基础；遇到干旱，给云层来一发干冰或碘化银炮弹，通过干冰降温或碘化银增加成核物质的手段增加降雨，也就成了最常见的人工降雨方式。不过，最近越来越多的科学家开始认为，除了天气变化，细菌也有很大可能控制着降雨。</p></li><li><p>故事要从50年前说起。1970年，科学家在研究雨水时，发现其中含有微量的维生素B₁₂。他们首先考虑，雨水由云层中的水蒸气凝结而成；云层中除了水蒸气，还有大量来自地表的灰尘，这些灰尘可能受人类活动影响而携带一些维生素B₁₂上天，导致雨水中维生素B₁₂的存在。不过在检查了云层中的灰尘后，他们发现云层中的灰尘含量与维生素B₁₂含量并没有什么关系。云只是一团堆积的水蒸气和灰尘，在排除人类活动干扰后，这些维生素B₁₂就只剩下一个来源——云层本身。</p></li><li><p>科学家开始猜测，可能是由于有大量微生物生活在云层中，在生命活动中产生了维生素B₁₂。不过由于当时技术条件有限，他们无法确定云层中到底存在哪些微生物。</p></li><li><p>基因测序技术的出现，让科学家有了彻底调查云层生态系统的能力。2017年，法国科学家在一个海拔1465米的气象站中采集到干净无污染的降水水样，对其进行基因测序。结果发现，水样中存在超过28000种微生物的DNA或RNA，其中细菌和古菌有22000多种，真核生物有2600多种。这些微生物中既有能够进行光合作用的细菌和藻类，也有异养细菌，它们可能构成了一个完整的生态链：光合作用生物利用云层中的水分和大气中的二氧化碳等合成有机物，异养细菌则可能会以光合作用生物为食。</p></li><li><p>云层中的紫外线极其强烈，很容易杀死位于高空的微生物。新的研究发现，其实有些细菌早就发展出抵抗紫外线的能力。无论是通过光合作用合成，还是通过掠食其他微生物获取，细菌们能将这些有机物分解为具有保护作用的胞外聚合物。这些物质基本由糖构成，类似一层“糖衣”，能够轻松抵御高空中的低温、干燥和紫外线破坏。穿孢杆菌就是最常见的能合成这种“糖衣”的细菌。该属包括许多种微生物，臭名昭著的炭疽杆菌就是其中之一。</p></li><li><p>近年来，随着人类活动越来越强烈，大量有机物的微小颗粒飘散到云层上，所形成的效应就是，微生物们可能躺在云层里“无所事事”，就能吃到足够的食物，很多人小时候曾经幻想天上的云朵就是棉花糖，盼望自己能飞到云层上大吃特吃，现在看来，细菌的生活就是我们的美梦。</p></li><li><p>每个带有防护性“糖衣”的细菌都相当于一个天然的凝结核，________________。 在天然条件下，云层中的纯水分子在低于-40℃时才会凝结；如果其中含有无机颗粒作为凝结核，凝结温度就会变成-15℃；一旦存在细菌水分子的凝结温度还会再次升高，有些细菌甚至能让水分子在-2℃时凝结。部分科学家相信，人类活动为微生物提供了童话般的生存环境，高空云层变得更为“宜居”，这就使得云层生态系统极度繁盛，这反过来将会引发频繁的雨雪。</p></li><li><p>当然，这还不是全部。还有一些科学家认为，增加降水本身就是云层微生物的一种生存策略。许多云层微生物是因为风力吹动而从地面直达空中的，它们会借助高空气流在空中远距离旅行一段时间，之后再通过变成凝结核的方式，以雨水的形式重回地表，寻找新的宿主。</p></li><li><p>此外，这些微生物在享受云层中的有机物颗粒时，会将它们重新分解为二氧化碳。如此一来，原本以固体颗粒形式存在的二氧化碳又被微生物释放到大气中，成为日益暖化的地球上又一根新的稻草。据估算，大气中每年因此增加的二氧化碳约为100万吨，数量虽少，却会随着人类排放的有机污染物数量增加而增加。这种暖化的结果就是：地表温度升高，蒸发加强，云层增多，云层生态系统更加繁荣。这么一想，细菌似乎成了控制地球气候的幕后黑手？</p></li><li><hr></li><li><p><strong>1.填入文中画横线部分最恰当的一项是：</strong></p></li><li><p>A.它的化学成分非常复杂</p></li><li><p>B.大大加速了雨雪的形成过程</p></li><li><p>C.其浓度会受地面环境影响</p></li><li><p>D.是促使大气中水汽凝结的微粒</p><details open="" style="box-sizing:border-box;"><summary style="box-sizing:border-box;touch-action:manipulation;margin:16px 0px;">解析</summary><blockquote style="box-sizing:border-box;margin:16px 0px;border-left:4px solid rgb(46, 46, 50);padding-left:16px;transition:border-color 0.5s;color:rgb(152, 152, 159);">横线出现在文段开头，且为首句的分句，应结合前面内容分析，并结合后文内容进行分析。<br style="box-sizing:border-box;">横线前的句子先引出“细菌”这一话题，并将其比作天然凝聚核，横线后论述不同凝结核的凝结温度存在差异，第七段最后一句引用了部分科学家的观点，即人类活动让高空云层变成微生物的“宜居”环境，繁盛的云层生态系统会引发频繁的雨雪。<br style="box-sizing:border-box;">第七段是“提出观点—解释说明”的“总—分”结构，首句应能概括文段内容，故横线处的观点应该与后面的结果话题一致，即细菌的出现最终会加速雨雪的形成。对比选项。B项符合上述语境。<br style="box-sizing:border-box;">A项，后文并未讲述其化学成分，衔接不当，排除；<br style="box-sizing:border-box;">C项，后文主要指出细菌可以加速水分子凝结从而加速雨雪形成，并未强调其浓度与地面环境的关系，“地面环境”无中生有，排除；<br style="box-sizing:border-box;">D项，后文重点强调细菌通过加速水分子凝结最终引发频繁的雨雪，并非仅表述其可以促使水汽凝结，排除。故正确答案为B。</blockquote></details></li><li><hr></li><li><p><strong>2.这篇文章没有对哪一技术或过程进行描述？</strong></p></li><li><p>A.光合作用</p></li><li><p>B.基因测序</p></li><li><p>C.天气预报</p></li><li><p>D.人工降雨</p><details open="" style="box-sizing:border-box;"><summary style="box-sizing:border-box;touch-action:manipulation;margin:16px 0px;">解析</summary><blockquote style="box-sizing:border-box;margin:16px 0px;border-left:4px solid rgb(46, 46, 50);padding-left:16px;transition:border-color 0.5s;color:rgb(152, 152, 159);">细节判断题，优先看每个段落的首尾句，能够大致了解每段的主题。<br style="box-sizing:border-box;">A项，根据第四段尾句“光合作用生物利用云层中的水分和大气中的二氧化碳等合成有机物，异养细菌则可能会以光合作用生物为食”可知，“光合作用”的过程文章已描述，排除；<br style="box-sizing:border-box;">B项，根据第四段开头“基因测序技术的出现，让科学家有了彻底调查云层生态系统的能力。2017年，法国科学家在一个海拔1465米的气象站中采集到干净无污染的降水水样，对其进行基因测序”可知，“基因测序”技术文章已描述，排除；<br style="box-sizing:border-box;">C项，根据第一段开头“降雨来源于云层，云层中的水蒸气遇到冷空气或某些成核物质后，就会很快冷凝而降落下来，所以冷暖空气相遇之处就是雨水多发的地带，这就是天气预报的基础”可知，文章仅描述了“天气预报的基础”，未描述何为“天气预报”的技术或过程，当选；<br style="box-sizing:border-box;">D项，根据第一段“遇到干旱，给云层来一发干冰或碘化银炮弹，通过干冰降温或碘化银增加成核物质的手段增加降雨，也就成了最常见的人工降雨方式”可知，“人工降雨”技术文章已描述，排除。<br style="box-sizing:border-box;">本题为选非题，故正确答案为C。</blockquote></details></li><li><hr></li><li><p><strong>3.下列哪项不是这篇文章中提到的科学家的研究结果？</strong></p></li><li><p>A.云层中的维生素B₁₂与微生物的生命活动有关</p></li><li><p>B.云层生态系统的活动提高了地球上的降水频率</p></li><li><p>C.空气中的二氧化碳浓度变化改变了植物的生长环境</p></li><li><p>D.某些高空微生物已经发展出抵抗强烈紫外线的能力</p><details open="" style="box-sizing:border-box;"><summary style="box-sizing:border-box;touch-action:manipulation;margin:16px 0px;">解析</summary><blockquote style="box-sizing:border-box;margin:16px 0px;border-left:4px solid rgb(46, 46, 50);padding-left:16px;transition:border-color 0.5s;color:rgb(152, 152, 159);">A项，根据第三段“科学家开始猜测，可能是由于有大量微生物生活在云层中，在生命活动中产生了维生素B₁₂”可知，云层中的维生素B₁₂与微生物的生命活动有关，文章已提及且表述正确，排除；<br style="box-sizing:border-box;">B项，根据第七段“部分科学家相信，人类活动为微生物提供了童话般的生存环境，高空云层变得更为‘宜居’，这就使得云层生态系统极度繁盛，这反过来将会引发频繁的雨雪”可知，云层生态系统的活动提高了地球上的降水频率，文章已提及且表述正确，排除；<br style="box-sizing:border-box;">C项，根据第九段“据估算，大气中每年因此增加的二氧化碳约为100万吨······这种暖化的结果就是：地表温度升高，蒸发加强，云层增多，云层生态系统更加繁荣”可知，文章并未提及“二氧化碳浓度变化”与“植物的生长环境”的关系，无中生有，当选；<br style="box-sizing:border-box;">D项，根据第五段“云层中的紫外线极其强烈，很容易杀死位于高空的微生物。新的研究发现，其实有些细菌早就发展出抵抗紫外线的能力”可知，某些高空微生物已经发展出抵抗强烈紫外线的能力，文章已提及且表述正确，排除。<br style="box-sizing:border-box;">本题为选非题，故正确答案为C。</blockquote></details></li><li><hr></li><li><p><strong>4.对最后一段中“成为日益暖化的地球上又一根新的稻草”理解最准确的是：</strong></p></li><li><p>A.可能使自然生态系统失去平衡</p></li><li><p>B.成为严重危害植物健康的病原体</p></li><li><p>C.成了导致地球气候恶化的罪魁祸首</p></li><li><p>D.致使地球温室效应更加严重</p><details open="" style="box-sizing:border-box;"><summary style="box-sizing:border-box;touch-action:manipulation;margin:16px 0px;">解析</summary><blockquote style="box-sizing:border-box;margin:16px 0px;border-left:4px solid rgb(46, 46, 50);padding-left:16px;transition:border-color 0.5s;color:rgb(152, 152, 159);">定位原文，“成为日益暖化的地球上又一根新的稻草”出现在最后一段第二句。分析“又一根新的稻草”的上下文语境。<br style="box-sizing:border-box;">句子前文论述的是微生物将云层中的有机物颗粒分解为二氧化碳，二氧化碳又被微生物释放到大气中，这一过程成为了日益暖化的地球上又一根新的稻草。<br style="box-sizing:border-box;">句子后文论述的是二氧化碳产生暖化的结果是地表温度升高。<br style="box-sizing:border-box;">故结合前后文可知，文段通过分析微生物释放出的二氧化碳及暖化结果来指出微生物具有让地球温度升高、变暖的作用，对应D项。<br style="box-sizing:border-box;">A项“自然生态系统失去平衡”、B项“严重危害植物健康”文段均未提及，无中生有，排除；<br style="box-sizing:border-box;">B项：“成为严重危害植物健康的病原体”，文段未提及微生物对植物健康的危害，属于无中生有，排除。<br style="box-sizing:border-box;">C项：“成了导致地球气候恶化的罪魁祸首”，“罪魁祸首”程度过重，文段说的是微生物释放二氧化碳会推动地球暖化，是众多影响因素之一，并非主要原因，表述不够明确，排除。<br style="box-sizing:border-box;">故正确答案为D。</blockquote></details></li><li><hr></li><li><p><strong>5.最适合做这篇文章标题的是：</strong></p></li><li><p>A.云层里可能住着控制气候的生灵</p></li><li><p>B.雨水中的维生素究竟来自哪里</p></li><li><p>C.活跃在万米高空的完整生态链</p></li><li><p>D.空中“棉花糖”里有哪些微生物</p><details open="" style="box-sizing:border-box;"><summary style="box-sizing:border-box;touch-action:manipulation;margin:16px 0px;">解析</summary><blockquote style="box-sizing:border-box;margin:16px 0px;border-left:4px solid rgb(46, 46, 50);padding-left:16px;transition:border-color 0.5s;color:rgb(152, 152, 159);">文章第一段论述了降雨的形成，并通过转折词“不过”引出细菌也有可能控制着降雨。<br style="box-sizing:border-box;">第二、三段论述了科学家猜测云层中有微生物，但由于当时技术有限无法确定有哪些微生物。<br style="box-sizing:border-box;">第四段论述了基因测序技术的出现，让科学家有了彻底调查云层生态系统的能力。<br style="box-sizing:border-box;">第五、六段举例论述了有些细菌发展出抵抗紫外线的能力并在云层中“无所事事”就能吃到足够的食物。<br style="box-sizing:border-box;">第七、八、九段从三个角度论述了微生物让云层生态系统繁荣，从而引发频繁的雨雪。<br style="box-sizing:border-box;">故文章主要介绍了云层中的微生物可能影响着气候的变化；对应A项。<br style="box-sizing:border-box;">B项，“维生素”仅对应文章第二、三段，并非文章论述的重点，排除；<br style="box-sizing:border-box;">C项，“完整生态链”仅对应文章第四段，并非文章论述的重点，且偏离文章核心话题，排除；<br style="box-sizing:border-box;">D项，文章重点论述云层中的微生物可能会对气候产生影响，而非讨论具体有哪些微生物，偏离文章核心话题，排除。<br style="box-sizing:border-box;">故正确答案为A。</blockquote></details></li></ol>',13)])])}const y=i(e,[["render",s]]);export{a as __pageData,y as default};
